        set { _password = value; }
    }

    public string FullName
    {
        get { return _fullName; }
        set { _fullName = value; }
    }

    public string Email
    {
        get { return _email; }
        set { _email = value; }
    }

    public string Address
    {
        get { return _address; }
        set { _address = value; }
    }

    // Collect all attributes into a list
    public List<string> ToList()
    {
        return new List<string>
        {
            _username,
            _password,
            _fullName,
            _email,
            _address
        };
    }
}
```

## 2. Serialization Helper

You can serialize either the whole object or the list. Here I'll use **JSON serialization** (modern, readable, and DB-friendly):

```csharp
using System.Collections.Generic;
using System.Text.Json;

public static class CustomerSerializer
{
    // Serialize the attribute list to a JSON string
    public static string SerializeAttributes(Customer customer)
    {
        List<string> attributes = customer.ToList();
        return JsonSerializer.Serialize(attributes);
    }

    // Deserialize back into a list
    public static List<string> DeserializeAttributes(string json)
    {
        return JsonSerializer.Deserialize<List<string>>(json);
    }
}
```

## 3. Save Serialized Data to the Database

Here's an example using **ADO.NET with SQL Server**. The serialized string is stored in a single column:

```csharp
using System;
using Microsoft.Data.SqlClient; // or System.Data.SqlClient

public class CustomerRepository
{
    private readonly string _connectionString;

    public CustomerRepository(string connectionString)
    {
        _connectionString = connectionString;
    }

    public void SaveCustomer(Customer customer)
    {
        // Convert attributes -> list -> serialized JSON
        string serializedData = CustomerSerializer.SerializeAttributes(customer);

        using (SqlConnection connection = new SqlConnection(_connectionString))
        {
            connection.Open();

            string query = @"INSERT INTO Customers (UserName, SerializedData) 
                             VALUES (@UserName, @SerializedData)";

            using (SqlCommand command = new SqlCommand(query, connection))
            {
                command.Parameters.AddWithValue("@UserName", customer.UserName);
                command.Parameters.AddWithValue("@SerializedData", serializedData);

                command.ExecuteNonQuery();
            }
        }
    }
}
```

## 4. Database Table

A simple table to hold the serialized payload:

```sql
CREATE TABLE Customers (
    Id INT IDENTITY(1,1) PRIMARY KEY,
    UserName NVARCHAR(100) NOT NULL,
    SerializedData NVARCHAR(MAX) NOT NULL
);
```

