### 1. `EncyclopediaInterface.java`

```java
import java.rmi.Remote;
import java.rmi.RemoteException;
import java.util.List;
import java.util.Map;

public interface EncyclopediaInterface extends Remote {

    // Returns the 300 random words stored on the server
    String[] getEncyclopedia() throws RemoteException;

    // 1- Number of letters (spaces included)
    int Count(String[] words) throws RemoteException;

    // 2- Words that are repeated
    List<String> repeatedwords(String[] words) throws RemoteException;

    // 3- Longest word
    String longest(String[] words) throws RemoteException;

    // 4- Shortest word
    String shortest(String[] words) throws RemoteException;

    // 5- Repetition number of each word
    Map<String, Integer> Repeat(String[] words) throws RemoteException;
}
```

---

### 2. `EncyclopediaImpl.java`

```java
import java.rmi.RemoteException;
import java.rmi.server.UnicastRemoteObject;
import java.util.*;

public class EncyclopediaImpl extends UnicastRemoteObject implements EncyclopediaInterface {

    private final String[] words;

    public EncyclopediaImpl() throws RemoteException {
        super();
        words = generateWords(300);
    }

    /* ---- Generate 300 random words from a small dictionary ---- */
    private String[] generateWords(int n) {
        String[] sample = {
            "apple", "river", "mountain", "sky", "ocean", "data", "computer",
            "thread", "encyclopedia", "random", "java", "network", "system",
            "speed", "process", "memory", "algorithm", "function", "object",
            "class", "method", "variable", "loop", "array", "string", "number",
            "machine", "intelligence", "code", "program", "server", "client",
            "remote", "interface", "registry", "speedup", "performance"
        };
        Random r = new Random();
        String[] result = new String[n];
        for (int i = 0; i < n; i++) {
            result[i] = sample[r.nextInt(sample.length)];
        }
        return result;
    }

    @Override
    public String[] getEncyclopedia() throws RemoteException {
        return words;
    }

    /* 1- Count letters, spaces included (a space between every two words) */
    @Override
    public int Count(String[] words) throws RemoteException {
        int count = 0;
        for (int i = 0; i < words.length; i++) {
            count += words[i].length();
            if (i < words.length - 1) {
                count++; // the space separating two words
            }
        }
        return count;
    }

    /* 2- Repeated words (appear more than once) */
    @Override
    public List<String> repeatedwords(String[] words) throws RemoteException {
        Map<String, Integer> map = new LinkedHashMap<>();
        for (String w : words) {
            map.merge(w, 1, Integer::sum);
        }
        List<String> repeated = new ArrayList<>();
        for (Map.Entry<String, Integer> e : map.entrySet()) {
            if (e.getValue() > 1) {
                repeated.add(e.getKey());
            }
        }
        return repeated;
    }

    /* 3- Longest word */
    @Override
    public String longest(String[] words) throws RemoteException {
        String longest = "";
        for (String w : words) {
            if (w.length() > longest.length()) {
                longest = w;
            }
        }
        return longest;
    }

    /* 4- Shortest word */
    @Override
    public String shortest(String[] words) throws RemoteException {
        String shortest = words[0];
        for (String w : words) {
            if (w.length() < shortest.length()) {
                shortest = w;
            }
        }
        return shortest;
    }

    /* 5- Repetition number of each word */
    @Override
    public Map<String, Integer> Repeat(String[] words) throws RemoteException {
        Map<String, Integer> map = new TreeMap<>();
        for (String w : words) {
            map.merge(w, 1, Integer::sum);
        }
        return map;
    }
}
```

