### 4. `EncyclopediaClient.java` (GUI)

```java
import javax.swing.*;
import java.awt.*;
import java.rmi.registry.LocateRegistry;
import java.rmi.registry.Registry;
import java.util.List;
import java.util.Map;

public class EncyclopediaClient extends JFrame {

    private EncyclopediaInterface service;
    private final JTextArea outputArea = new JTextArea();

    private double nonThreadedTime = 0;
    private double threadedTime = 0;

    public EncyclopediaClient() {
        super("RMI Encyclopedia Analyzer (300 words)");

        // ---- Connect to RMI service ----
        try {
            Registry registry = LocateRegistry.getRegistry("localhost", 1099);
            service = (EncyclopediaInterface) registry.lookup("EncyclopediaService");
        } catch (Exception e) {
            JOptionPane.showMessageDialog(this,
                    "Cannot connect to RMI server.\nStart EncyclopediaServer first.\n\n" + e,
                    "Connection Error", JOptionPane.ERROR_MESSAGE);
        }

        // ---- Build GUI ----
        JButton nonThreadedBtn = new JButton("Run Non-Threaded");
        JButton threadedBtn     = new JButton("Run Multi-Threaded");
        JButton speedupBtn      = new JButton("Show Speedup");

        JPanel buttons = new JPanel();
        buttons.add(nonThreadedBtn);
        buttons.add(threadedBtn);
        buttons.add(speedupBtn);

        outputArea.setEditable(false);
        outputArea.setFont(new Font("Monospaced", Font.PLAIN, 13));
        JScrollPane scroll = new JScrollPane(outputArea);

        add(buttons, BorderLayout.NORTH);
        add(scroll, BorderLayout.CENTER);

        nonThreadedBtn.addActionListener(e -> runNonThreaded());
        threadedBtn.addActionListener(e -> runThreaded());
        speedupBtn.addActionListener(e -> showSpeedup());

        setSize(700, 600);
        setLocationRelativeTo(null);
        setDefaultCloseOperation(EXIT_ON_CLOSE);
    }

    /* ---------------- NON-THREADED VERSION ---------------- */
    private void runNonThreaded() {
        try {
            String[] words = service.getEncyclopedia();

            long start = System.nanoTime();

            int totalLetters       = service.Count(words);
            List<String> repeated  = service.repeatedwords(words);
            String longestWord     = service.longest(words);
            String shortestWord    = service.shortest(words);
            Map<String, Integer> repeatMap = service.Repeat(words);

            long end = System.nanoTime();
            nonThreadedTime = (end - start) / 1_000_000.0; // ms

            displayResults("NON-THREADED", words.length, totalLetters,
                    repeated, longestWord, shortestWord, repeatMap, nonThreadedTime);

        } catch (Exception ex) {
            outputArea.setText("Error: " + ex);
        }
    }

    /* ---------------- MULTI-THREADED VERSION ---------------- */
    private void runThreaded() {
        try {
            final String[] words = service.getEncyclopedia();

            // Shared holders for results computed by threads
            final int[] countResult              = new int[1];
            @SuppressWarnings("unchecked")
            final List<String>[] repeatedResult  = new List[1];
            final String[] longestResult         = new String[1];
            final String[] shortestResult        = new String[1];
            @SuppressWarnings("unchecked")
            final Map<String, Integer>[] repeatResult = new Map[1];

            long start = System.nanoTime();

            Thread t1 = new Thread(() -> {
                try { countResult[0] = service.Count(words); } catch (Exception ignored) {}
            });
            Thread t2 = new Thread(() -> {
                try { repeatedResult[0] = service.repeatedwords(words); } catch (Exception ignored) {}
            });
            Thread t3 = new Thread(() -> {
                try { longestResult[0] = service.longest(words); } catch (Exception ignored) {}
            });
            Thread t4 = new Thread(() -> {
                try { shortestResult[0] = service.shortest(words); } catch (Exception ignored) {}
            });
            Thread t5 = new Thread(() -> {
                try { repeatResult[0] = service.Repeat(words); } catch (Exception ignored) {}
            });

            t1.start(); t2.start(); t3.start(); t4.start(); t5.start();
            t1.join();  t2.join();  t3.join();  t4.join();  t5.join();

            long end = System.nanoTime();
            threadedTime = (end - start) / 1_000_000.0; // ms

            displayResults("MULTI-THREADED", words.length, countResult[0],
                    repeatedResult[0], longestResult[0], shortestResult[0],
                    repeatResult[0], threadedTime);

        } catch (Exception ex) {
            outputArea.setText("Error: " + ex);
        }
    }

    /* ---------------- SPEEDUP ---------------- */
    private void showSpeedup() {
        if (nonThreadedTime == 0 || threadedTime == 0) {
            JOptionPane.showMessageDialog(this,
                    "Run BOTH the non-threaded and multi-threaded versions first.",
                    "Info", JOptionPane.INFORMATION_MESSAGE);
            return;
        }

        double speedupMs = nonThreadedTime - threadedTime;
        double ratio = nonThreadedTime / threadedTime;

        StringBuilder sb = new StringBuilder();
        sb.append("==================== SPEEDUP ====================\n");
        sb.append(String.format("Non-Threaded time : %.4f ms%n", nonThreadedTime));
        sb.append(String.format("Multi-Threaded time: %.4f ms%n", threadedTime));
        sb.append("-------------------------------------------------\n");
        sb.append(String.format("Time saved (speedup): %.4f ms%n", speedupMs));
        sb.append(String.format("Speedup ratio        : %.2fx%n", ratio));
        sb.append("=================================================\n");

        outputArea.setText(sb.toString());
    }

    /* ---------------- DISPLAY HELPER ---------------- */
    private void displayResults(String title, int wordCount, int letters,
                                List<String> repeated, String longest,
                                String shortest, Map<String, Integer> repeatMap,
                                double timeMs) {

        StringBuilder sb = new StringBuilder();
        sb.append("==================== ").append(title).append(" ====================\n");
        sb.append("Total words: ").append(wordCount).append("\n\n");

        sb.append("1- Count (letters incl. spaces): ").append(letters).append("\n\n");

        sb.append("2- Repeated words (").append(repeated.size()).append("):\n");
        sb.append("   ").append(repeated).append("\n\n");

        sb.append("3- Longest word : ").append(longest)
          .append(" (").append(longest.length()).append(" letters)\n\n");

        sb.append("4- Shortest word: ").append(shortest)
          .append(" (").append(shortest.length()).append(" letters)\n\n");

        sb.append("5- Repeat (each word's count):\n");
        for (Map.Entry<String, Integer> e : repeatMap.entrySet()) {
            sb.append(String.format("   %-15s : %d%n", e.getKey(), e.getValue()));
        }

        sb.append("\n>>> Execution time: ").append(String.format("%.4f", timeMs)).append(" ms\n");

        outputArea.setText(sb.toString());
    }

    public static void main(String[] args) {
        SwingUtilities.invokeLater(() -> new EncyclopediaClient().setVisible(true));
    }
}
```

