Чтобы каждая **вершина** (точка) имела свой случайный цвет, нужно создать атрибут `color` в геометрии и включить `vertexColors: true` в материале. Сам `color` материала тогда задавать не нужно.

Вот исправленный фрагмент:

```javascript
model.traverse((child) => {
  if (child.isMesh) {
    const geometry = child.geometry;

    // Количество вершин
    const count = geometry.attributes.position.count;

    // Массив для цветов (по 3 значения RGB на вершину)
    const colors = new Float32Array(count * 3);
    for (let i = 0; i < count; i++) {
      colors[i * 3 + 0] = Math.random(); // R
      colors[i * 3 + 1] = Math.random(); // G
      colors[i * 3 + 2] = Math.random(); // B
    }

    // Добавляем атрибут цвета в геометрию
    geometry.setAttribute('color', new THREE.BufferAttribute(colors, 3));

    // Материал с включёнными вершинными цветами
    const material = new THREE.PointsMaterial({
      size: 0.05,
      vertexColors: true // используем цвета из атрибута geometry
    });

    const points = new THREE.Points(geometry, material);
    child.parent.add(points);
    child.parent.remove(child);
  }
});
```

### Что изменилось:
1. **`geometry.attributes.position.count`** — получаем количество вершин в меше.
2. **Создаём `Float32Array`** размером `count * 3` (по три компоненты RGB на каждую вершину).
3. **Заполняем массив** случайными значениями для R, G, B.
4. **`geometry.setAttribute('color', ...)`** — добавляем атрибут цвета в геометрию.
5. В материале вместо `color` ставим **`vertexColors: true`**, чтобы Three.js брал цвет из атрибута каждой вершины.

Теперь каждая точка (вершина) будет окрашена в свой собственный случайный цвет, а не все точки одним цветом.

# Golang Telegram Bot Example

Here's a complete example using the popular `go-telegram-bot-api` library.

## Installation

```bash
go mod init telegram-bot
go get github.com/go-telegram-bot-api/telegram-bot-api/v5
```

## Basic Echo Bot

```go
package main

import (
	"log"

	tgbotapi "github.com/go-telegram-bot-api/telegram-bot-api/v5"
)

func main() {
	// Replace with your bot token from @BotFather
	bot, err := tgbotapi.NewBotAPI("YOUR_BOT_TOKEN")
	if err != nil {
		log.Panic(err)
	}

	bot.Debug = true
	log.Printf("Authorized on account %s", bot.Self.UserName)

	// Configure updates
	u := tgbotapi.NewUpdate(0)
	u.Timeout = 60

	updates := bot.GetUpdatesChan(u)

	// Listen for updates
	for update := range updates {
		if update.Message == nil { // ignore non-message updates
			continue
		}

		log.Printf("[%s] %s", update.Message.From.UserName, update.Message.Text)

		// Echo the message back
		msg := tgbotapi.NewMessage(update.Message.Chat.ID, update.Message.Text)
		msg.ReplyToMessageID = update.Message.MessageID

		bot.Send(msg)
	}
}
```

## Bot with Commands

```go
package main

import (
	"log"

	tgbotapi "github.com/go-telegram-bot-api/telegram-bot-api/v5"
)

func main() {
	bot, err := tgbotapi.NewBotAPI("YOUR_BOT_TOKEN")
	if err != nil {
		log.Panic(err)
	}

	log.Printf("Authorized on account %s", bot.Self.UserName)

	u := tgbotapi.NewUpdate(0)
	u.Timeout = 60

	updates := bot.GetUpdatesChan(u)

	for update := range updates {
		if update.Message == nil {
			continue
		}

		// Handle commands
		if update.Message.IsCommand() {
			msg := tgbotapi.NewMessage(update.Message.Chat.ID, "")

			switch update.Message.Command() {
			case "start":
				msg.Text = "Welcome! I'm your bot. Type /help for commands."
			case "help":
				msg.Text = "Available commands:\n/start - Start the bot\n/help - Show help\n/ping - Test response"
			case "ping":
				msg.Text = "Pong! 🏓"
			default:
				msg.Text = "Unknown command. Type /help."
			}

			bot.Send(msg)
			continue
		}

		// Handle regular messages
		msg := tgbotapi.NewMessage(update.Message.Chat.ID, "You said: "+update.Message.Text)
		bot.Send(msg)
	}
}
