		log.Panic(err)
	}

	// Set webhook
	wh, _ := tgbotapi.NewWebhook("https://yourdomain.com/" + bot.Token)
	_, err = bot.Request(wh)
	if err != nil {
		log.Fatal(err)
	}

	updates := bot.ListenForWebhook("/" + bot.Token)

	go http.ListenAndServe("0.0.0.0:8443", nil)

	for update := range updates {
