# MQL5 Neural Network with Ichimoku and RSI for Price Targets

Here's a complete MQL5 indicator that uses a simple neural network (neuron) to process Ichimoku and RSI data to predict possible price targets.

```mql5
//+------------------------------------------------------------------+
//|                                          NeuronIchimokuRSI.mq5    |
//|                        Neural Network Price Target Predictor      |
//+------------------------------------------------------------------+
#property copyright "Neural Target Predictor"
#property version   "1.00"
#property indicator_chart_window
#property indicator_buffers 2
#property indicator_plots   2

//--- Plot Bullish Target
#property indicator_label1  "BullishTarget"
#property indicator_type1   DRAW_LINE
#property indicator_color1  clrLime
#property indicator_width1  2

//--- Plot Bearish Target
#property indicator_label2  "BearishTarget"
#property indicator_type2   DRAW_LINE
#property indicator_color2  clrRed
#property indicator_width2  2

//--- Input parameters
input int    TenkanPeriod   = 9;      // Ichimoku Tenkan-sen
input int    KijunPeriod    = 26;     // Ichimoku Kijun-sen
input int    SenkouPeriod   = 52;     // Ichimoku Senkou Span B
input int    RSIPeriod      = 14;     // RSI Period
input double LearningRate    = 0.01;  // Neural learning rate
input int    TrainingBars   = 500;    // Bars for training

//--- Indicator buffers
double BullishTargetBuffer[];
double BearishTargetBuffer[];

//--- Indicator handles
int    ichimokuHandle;
int    rsiHandle;

//--- Neural network weights (single neuron with multiple inputs)
//--- Inputs: Tenkan, Kijun, SpanA, SpanB, Chikou, RSI = 6 inputs
double weights[6];
double bias;

//+------------------------------------------------------------------+
//| Custom indicator initialization function                         |
//+------------------------------------------------------------------+
int OnInit()
  {
//--- Map buffers
   SetIndexBuffer(0, BullishTargetBuffer, INDICATOR_DATA);
   SetIndexBuffer(1, BearishTargetBuffer, INDICATOR_DATA);

//--- Create indicator handles
   ichimokuHandle = iIchimoku(_Symbol, _Period, TenkanPeriod, KijunPeriod, SenkouPeriod);
   rsiHandle      = iRSI(_Symbol, _Period, RSIPeriod, PRICE_CLOSE);

   if(ichimokuHandle == INVALID_HANDLE || rsiHandle == INVALID_HANDLE)
     {
      Print("Error creating indicator handles");
      return(INIT_FAILED);
     }

//--- Initialize neuron weights with small random values
   InitializeNeuron();

   return(INIT_SUCCEEDED);
  }

//+------------------------------------------------------------------+
//| Initialize neuron weights randomly                               |
//+------------------------------------------------------------------+
void InitializeNeuron()
  {
   MathSrand((int)TimeCurrent());
   for(int i = 0; i < 6; i++)
      weights[i] = (MathRand() / 32767.0 - 0.5) * 0.1;
   bias = (MathRand() / 32767.0 - 0.5) * 0.1;
  }

//+------------------------------------------------------------------+
//| Activation function (tanh) - returns -1 to 1                     |
//+------------------------------------------------------------------+
double Activation(double x)
  {
   return MathTanh(x);
  }

//+------------------------------------------------------------------+
//| Derivative of tanh for backpropagation                          |
//+------------------------------------------------------------------+
double ActivationDerivative(double x)
  {
   double t = MathTanh(x);
   return 1.0 - t * t;
  }

//+------------------------------------------------------------------+
//| Normalize value to 0-1 range based on price                     |
//+------------------------------------------------------------------+
double NormalizePrice(double value, double price)
  {
   if(price == 0) return 0;
   return (value - price) / price; // relative deviation
  }

//+------------------------------------------------------------------+
//| Forward pass through the neuron                                  |
//+------------------------------------------------------------------+
double NeuronForward(double &inputs[], double &netInput)
  {
   double sum = bias;
   for(int i = 0; i < 6; i++)
      sum += weights[i] * inputs[i];

   netInput = sum;
   return Activation(sum);
  }

//+------------------------------------------------------------------+
//| Train neuron on a single sample (backpropagation)               |
//+------------------------------------------------------------------+
void TrainNeuron(double &inputs[], double targetOutput)
  {
   double netInput;
   double output = NeuronForward(inputs, netInput);

   //--- Calculate error
   double error = targetOutput - output;

   //--- Calculate gradient
   double gradient = error * ActivationDerivative(netInput);

   //--- Update weights and bias
   for(int i = 0; i < 6; i++)
      weights[i] += LearningRate * gradient * inputs[i];

   bias += LearningRate * gradient;
  }

//+------------------------------------------------------------------+
//| Gather neural inputs for a given bar shift                       |
//+------------------------------------------------------------------+
bool GetNeuralInputs(int shift, double &inputs[])
  {
   double tenkan[], kijun[], spanA[], spanB[], chikou[], rsi[];

   //--- Copy Ichimoku lines
   if(CopyBuffer(ichimokuHandle, 0, shift, 1, tenkan) <= 0) return false;
   if(CopyBuffer(ichimokuHandle, 1, shift, 1, kijun)  <= 0) return false;
   if(CopyBuffer(ichimokuHandle, 2, shift, 1, spanA)  <= 0) return false;
   if(CopyBuffer(ichimokuHandle, 3, shift, 1, spanB)  <= 0) return false;
   if(CopyBuffer(ichimokuHandle, 4, shift, 1, chikou) <= 0) return false;

   //--- Copy RSI
   if(CopyBuffer(rsiHandle, 0, shift, 1, rsi) <= 0) return false;

   //--- Get current close for normalization
   double closePrice[];
   if(CopyClose(_Symbol, _Period, shift, 1, closePrice) <= 0) return false;
   double price = closePrice[0];

   //--- Build normalized input vector
   inputs[0] = NormalizePrice(tenkan[0], price);
   inputs[1] = NormalizePrice(kijun[0], price);
   inputs[2] = NormalizePrice(spanA[0], price);
   inputs[3] = NormalizePrice(spanB[0], price);
   inputs[4] = NormalizePrice(chikou[0], price);
   inputs[5] = (rsi[0] - 50.0) / 50.0; // normalize RSI to -1..1

   return true;
  }

//+------------------------------------------------------------------+
//| Train the neuron over historical data                           |
//+------------------------------------------------------------------+
void TrainNetwork(int totalBars)
  {
   int trainCount = MathMin(TrainingBars, totalBars - SenkouPeriod - 30);
   if(trainCount <= 0) return;

   //--- Multiple training epochs
   for(int epoch = 0; epoch < 5; epoch++)
     {
      for(int i = trainCount; i > 1; i--)
        {
         double inputs[6];
         if(!GetNeuralInputs(i, inputs)) continue;

         //--- Target: future price direction (looking 5 bars ahead)
         double futureClose[], currentClose[];
         if(CopyClose(_Symbol, _Period, i - 5, 1, futureClose) <= 0) continue;
         if(CopyClose(_Symbol, _Period, i, 1, currentClose) <= 0) continue;

         //--- Target output: normalized future movement (-1 to 1)
         double movement = (futureClose[0] - currentClose[0]) / currentClose[0];
         double target = MathTanh(movement * 100); // scale movement

         TrainNeuron(inputs, target);
        }
     }
  }

//+------------------------------------------------------------------+
//| Custom indicator iteration function                              |
//+------------------------------------------------------------------+
int OnCalculate(const int rates_total,
                const int prev_calculated,
                const datetime &time[],
                const double &open[],
                const double &high[],
                const double &low[],
                const double &close[],
                const long &tick_volume[],
                const long &volume[],
                const int &spread[])
  {
   if(rates_total < SenkouPeriod + 50)
      return(0);

   //--- Train the network once when fully loaded
   static bool trained = false;
   if(!trained && prev_calculated == 0)
     {
      TrainNetwork(rates_total);
      trained = true;
      Print("Neural network training complete.");
     }

//--- Calculate predictions
   int start = (prev_calculated > 0) ? prev_calculated - 1 : SenkouPeriod + 30;

   for(int i = start; i < rates_total - 1; i++)
     {
      int shift = rates_total - 1 - i;

      double inputs[6];
      if(!GetNeuralInputs(shift, inputs))
        {
         BullishTargetBuffer[i] = EMPTY_VALUE;
         BearishTargetBuffer[i] = EMPTY_VALUE;
         continue;
        }

      //--- Get neuron output (-1 to 1 prediction)
      double netInput;
      double prediction = NeuronForward(inputs, netInput);

      //--- Compute Average True Range for target scaling
      double atrPrice = MathAbs(high[i] - low[i]);
      if(atrPrice == 0) atrPrice = _Point * 10;

      //--- Scale prediction into price target distance
      double range = atrPrice * 5.0 * MathAbs(prediction);

      //--- Set targets based on prediction direction
      if(prediction > 0)
        {
         //--- Bullish bias
         BullishTargetBuffer[i] = close[i] + range;
         BearishTargetBuffer[i] = EMPTY_VALUE;
        }
      else
        {
         //--- Bearish bias
         BearishTargetBuffer[i] = close[i] - range;
         BullishTargetBuffer[i] = EMPTY_VALUE;
        }
     }

//--- Display current prediction info
   double curInputs[6];
   if(GetNeuralInputs(0, curInputs))
     {
      double net;
      double pred = NeuronForward(curInputs, net);
      string bias = (pred > 0) ? "BULLISH" : "BEARISH";
      double confidence = MathAbs(pred) * 100;
      Comment(StringFormat("Neural Prediction: %s\nConfidence: %.1f%%\nRaw Output: %.4f",
                           bias, confidence, pred));
     }

   return(rates_total);
  }

//+------------------------------------------------------------------+
//| Deinitialization                                                 |
//+------------------------------------------------------------------+
void OnDeinit(const int reason)
  {
   if(ichimokuHandle != INVALID_HANDLE) IndicatorRelease(ichimokuHandle);
   if(rsiHandle != INVALID_HANDLE)      IndicatorRelease(rsiHandle);
   Comment("");
  }
//+------------------------------------------------------------------+
```

## How It Works

**🧠 Neural Architecture**
- A **single neuron** with **6 inputs** (5 Ichimoku lines + RSI)
- Uses **tanh activation** (output range -1 to +1)
- Trained via **backpropagation** (gradient descent)

**📊 Inputs Fed to the Neuron**

| Input | Source | Normalization |
|-------|--------|---------------|
| 1 | Tenkan-sen | Relative to price |
| 2 | Kijun-sen | Relative to price |
| 3 | Senkou Span A | Relative to price |
| 4 | Senkou Span B | Relative to price |
| 5 | Chikou Span | Relative to price |
| 6 | RSI | Scaled to -1..1 |

**🎯 Output**
- **Positive output** → Bullish target plotted (green line above price)
- **Negative output** → Bearish target plotted (red line below price)
- Target distance is scaled by bar range × confidence

## Key Features
- Self-trains on historical data (looks 5 bars ahead during training)
- Displays live prediction direction and confidence in the chart comment
- Targets adapt dynamically based on market volatility

