# Tetris-Style Word Game in p5.js

Here's a complete word-stacking game where word blocks fall Tetris-style and you guide them into matching target slots:

```html
<!DOCTYPE html>
<html>
<head>
  <meta charset="utf-8">
  <title>Body Parts Word Tetris</title>
  <script src="https://cdnjs.cloudflare.com/ajax/libs/p5.js/1.9.0/p5.min.js"></script>
  <style>
    body { margin: 0; background: #1a1a2e; display: flex; justify-content: center; }
  </style>
</head>
<body>
<script>
// ---- Word list ----
const WORDS = ["Head","Face","Eye","Ear","Nose","Mouth","Teeth","Tongue","Neck","Shoulder"];

// ---- Layout constants ----
const COLS = 5;            // number of columns / slots
const CELL_W = 120;        // column width
const CELL_H = 50;         // block height
const TOP = 60;            // top of play field
const BOTTOM = 620;        // floor / target row top

let activeWord;            // {text, col, y}
let targets = [];         // target slots at bottom (the words to match)
let score = 0;
let speed = 1.5;
let gameOver = false;
let placedBlocks = [];    // {text, col, y, correct}

function setup() {
  createCanvas(COLS * CELL_W, 720);
  textAlign(CENTER, CENTER);
  textSize(20);
  newTargets();
  spawnWord();
}

// Pick 5 random words to be the target slots
function newTargets() {
  let shuffled = [...WORDS].sort(() => random() - 0.5);
  targets = shuffled.slice(0, COLS);
}

// Spawn a new falling word that matches one of the remaining targets
function spawnWord() {
  // choose a target that hasn't been filled yet
  let remaining = targets.filter(t => !placedBlocks.some(b => b.text === t && b.correct));
  if (remaining.length === 0) {
    // round complete - new round
    placedBlocks = [];
    score += 50; // bonus
    newTargets();
    remaining = [...targets];
  }
  let word = random(remaining);
  activeWord = { text: word, col: floor(COLS / 2), y: TOP };
}

function draw() {
  background(26, 26, 46);

  drawGrid();
  drawTargets();
  drawPlaced();

  if (!gameOver) {
    updateActive();
    drawBlock(activeWord.col, activeWord.y, activeWord.text, color(86, 204, 242));
  }

  drawHUD();

  if (gameOver) {
    fill(0, 180);
    rect(0, 0, width, height);
    fill(255);
    textSize(40);
    text("GAME OVER", width/2, height/2 - 20);
    textSize(22);
    text("Score: " + score, width/2, height/2 + 30);
    text("Press R to restart", width/2, height/2 + 70);
  }
}

function updateActive() {
  activeWord.y += speed;

  // landing height for the column (stack on placed blocks)
  let stackTop = BOTTOM;
  let colBlocks = placedBlocks.filter(b => b.col === activeWord.col);
  stackTop = BOTTOM - colBlocks.length * CELL_H;

  if (activeWord.y + CELL_H >= stackTop) {
    activeWord.y = stackTop - CELL_H;
    placeWord();
  }
}

function placeWord() {
  let correct = (targets[activeWord.col] === activeWord.text);
  placedBlocks.push({
    text: activeWord.text,
    col: activeWord.col,
    y: activeWord.y,
    correct: correct
  });

  if (correct) {
    score += 10;
  } else {
    score = max(0, score - 5);
    // if a wrong block is placed and stack reaches the top → game over
    if (activeWord.y <= TOP) {
      gameOver = true;
      return;
    }
  }
  spawnWord();
}

// ---- Drawing helpers ----
function drawGrid() {
  stroke(60);
  for (let c = 0; c <= COLS; c++) {
    line(c * CELL_W, TOP, c * CELL_W, BOTTOM + CELL_H);
  }
  noStroke();
}

function drawTargets() {
  for (let c = 0; c < COLS; c++) {
    fill(40, 40, 70);
    stroke(120, 120, 200);
    rect(c * CELL_W + 4, BOTTOM + 4, CELL_W - 8, CELL_H - 8, 8);
    noStroke();
    fill(150, 150, 220);
    textSize(16);
    text("→ " + targets[c], c * CELL_W + CELL_W/2, BOTTOM + CELL_H/2);
  }
}

function drawPlaced() {
  for (let b of placedBlocks) {
    let col = b.correct ? color(39, 174, 96) : color(192, 57, 43);
    drawBlock(b.col, b.y, b.text, col);
  }
}

function drawBlock(col, y, txt, col_color) {
  let x = col * CELL_W;
  fill(col_color);
  stroke(255, 60);
  rect(x + 4, y + 2, CELL_W - 8, CELL_H - 4, 8);
  noStroke();
  fill(255);
  textSize(20);
  text(txt, x + CELL_W/2, y + CELL_H/2);
}

function drawHUD() {
  fill(255);
  textSize(22);
  textAlign(LEFT, CENTER);
  text("Score: " + score, 10, 30);
  textAlign(RIGHT, CENTER);
  text("← → move   ↓ drop", width - 10, 30);
  textAlign(CENTER, CENTER);
}

// ---- Controls ----
function keyPressed() {
  if (gameOver) {
    if (key === 'r' || key === 'R') restart();
    return;
  }
  if (keyCode === LEFT_ARROW)  activeWord.col = max(0, activeWord.col - 1);
  if (keyCode === RIGHT_ARROW) activeWord.col = min(COLS - 1, activeWord.col + 1);
  if (keyCode === DOWN_ARROW)  activeWord.y += 40;  // soft drop
  if (key === ' ') {                                 // hard drop
    let colBlocks = placedBlocks.filter(b => b.col === activeWord.col);
    activeWord.y = BOTTOM - colBlocks.length * CELL_H - CELL_H;
    placeWord();
  }
}

function restart() {
  score = 0;
  gameOver = false;
  placedBlocks = [];
  newTargets();
  spawnWord();
}
</script>
</body>
</html>
```

## How it works

**Goal:** Guide each falling word block into the column whose target slot (shown at the bottom) matches that word.

**Controls:**
- **← →** Move the block left/right between columns
- **↓** Soft drop (fall faster)
- **Spacebar** Hard drop (instant)
- **R** Restart after game over

**Scoring & rules:**
- ✅ Correct match (green) = **+10 points**
- ❌ Wrong column (red, stacks up) = **−5 points**
- Complete all 5 slots in a round = **+50 bonus** and new target words appear
- If wrong blocks stack to the top, it's **game over**

## Easy ways to customize

| Want to change... | Edit this |
|---|---|
| Difficulty | `let speed = 1.5;` (higher = faster) |
| Number of columns | `const COLS = 5;` |
| The words | the `WORDS` array at the top |
| Block size | `CELL_W` and `CELL_H` |

