        Customer customer = new Customer(name, email, age);

        // 3. Insert into database
        InsertCustomer(customer);

        MessageBox.Show("Customer saved successfully!");
        ClearForm();
    }
    catch (Exception ex)
    {
        MessageBox.Show("Error: " + ex.Message);
    }
}
```

## 3. The Database Insert Method

Using **ADO.NET** with `SqlConnection` (for SQL Server). **Always use parameterized queries** to prevent SQL injection:

```csharp
using System.Data.SqlClient;  // add this at the top

private void InsertCustomer(Customer customer)
{
    // Adjust connection string to match your database
    string connectionString = 
        @"Server=.\SQLEXPRESS;Database=MyDatabase;Integrated Security=True;";

    string query = @"INSERT INTO Customers (Name, Email, Age) 
                     VALUES (@Name, @Email, @Age)";

    using (SqlConnection conn = new SqlConnection(connectionString))
    using (SqlCommand cmd = new SqlCommand(query, conn))
    {
        // Use parameters (safe from SQL injection)
        cmd.Parameters.AddWithValue("@Name", customer.Name);
        cmd.Parameters.AddWithValue("@Email", customer.Email);
        cmd.Parameters.AddWithValue("@Age", customer.Age);

        conn.Open();
        cmd.ExecuteNonQuery();
    }
}
```

## 4. Helper to Clear the Form

```csharp
private void ClearForm()
{
    txtName.Clear();
    txtEmail.Clear();
    txtAge.Clear();
    txtName.Focus();
}
```

---

## Key Points

| Topic | Note |
|-------|------|
| **Parameterized queries** | Always use `@param` instead of string concatenation to prevent SQL injection |
| **`using` statement** | Automatically closes/disposes the connection even if an error occurs |
| **`TryParse`** | Safely converts text to numbers without crashing |
| **Connection string** | Must match your actual database server/name |

