# Converting Baileys Multi-Device Connection to Zig

I'll help you create a Zig implementation for connecting to WhatsApp's multi-device API using Baileys-compatible auth files. This is a substantial undertaking, so let me break it down into the core components.

## Project Structure

```
baileys-zig/
├── build.zig
├── src/
│   ├── main.zig
│   ├── auth/
│   │   ├── state.zig
│   │   └── keys.zig
│   ├── crypto/
│   │   ├── noise.zig
│   │   ├── curve25519.zig
│   │   └── signal.zig
│   ├── socket/
│   │   ├── websocket.zig
│   │   └── connection.zig
│   └── binary/
│       ├── encoder.zig
│       └── decoder.zig
```

## build.zig

```zig
const std = @import("std");

pub fn build(b: *std.Build) void {
    const target = b.standardTargetOptions(.{});
    const optimize = b.standardOptimizeOption(.{});

    const exe = b.addExecutable(.{
        .name = "baileys-zig",
        .root_source_file = b.path("src/main.zig"),
        .target = target,
        .optimize = optimize,
    });

    // Link required crypto libraries
    exe.linkLibC();
    exe.linkSystemLibrary("crypto");

    b.installArtifact(exe);

    const run_cmd = b.addRunArtifact(exe);
    run_cmd.step.dependOn(b.getInstallStep());

    const run_step = b.step("run", "Run the app");
    run_step.dependOn(&run_cmd.step);
}
```

## Auth State (Baileys-Compatible)

The key insight is that Baileys stores auth as JSON with Base64-encoded binary data.

```zig
// src/auth/state.zig
const std = @import("std");
const json = std.json;

pub const KeyPair = struct {
    public: [32]u8,
    private: [32]u8,
};

pub const SignedKeyPair = struct {
    keyPair: KeyPair,
    signature: [64]u8,
    keyId: u32,
};

pub const Creds = struct {
    noiseKey: KeyPair,
    pairingEphemeralKeyPair: KeyPair,
    signedIdentityKey: KeyPair,
    signedPreKey: SignedKeyPair,
    registrationId: u32,
    advSecretKey: [32]u8,
    me: ?struct {
        id: []const u8,
        name: ?[]const u8 = null,
    } = null,
    account: ?struct {
        details: []const u8,
        accountSignatureKey: []const u8,
        accountSignature: []const u8,
        deviceSignature: []const u8,
    } = null,
    platform: ?[]const u8 = null,
    nextPreKeyId: u32 = 1,
    firstUnuploadedPreKeyId: u32 = 1,

    pub fn deinit(self: *Creds, allocator: std.mem.Allocator) void {
        if (self.me) |me| {
            allocator.free(me.id);
            if (me.name) |n| allocator.free(n);
        }
        // free account fields if present
    }
};

/// Baileys stores binary data as { "type": "Buffer", "data": [...] }
/// or as Base64 strings depending on version
const BufferJson = struct {
    type: []const u8,
    data: []u8,
};

pub const AuthState = struct {
    creds: Creds,
    allocator: std.mem.Allocator,

    pub fn loadFromFile(allocator: std.mem.Allocator, path: []const u8) !AuthState {
        const file = try std.fs.cwd().openFile(path, .{});
        defer file.close();

        const contents = try file.readToEndAlloc(allocator, 10 * 1024 * 1024);
        defer allocator.free(contents);

        return try parseCredsJson(allocator, contents);
    }

    pub fn saveToFile(self: *AuthState, path: []const u8) !void {
        const file = try std.fs.cwd().createFile(path, .{});
        defer file.close();

        try serializeCredsJson(self.allocator, file.writer(), &self.creds);
    }

    pub fn deinit(self: *AuthState) void {
        self.creds.deinit(self.allocator);
    }
};

/// Parse Baileys creds.json format
fn parseCredsJson(allocator: std.mem.Allocator, data: []const u8) !AuthState {
    const parsed = try json.parseFromSlice(json.Value, allocator, data, .{});
    defer parsed.deinit();

    const root = parsed.value.object;

    var creds: Creds = undefined;

    // Parse noiseKey
    creds.noiseKey = try parseKeyPair(allocator, root.get("noiseKey").?);
    creds.signedIdentityKey = try parseKeyPair(allocator, root.get("signedIdentityKey").?);
    creds.pairingEphemeralKeyPair = try parseKeyPair(allocator, root.get("pairingEphemeralKeyPair").?);

    // Parse signedPreKey
    creds.signedPreKey = try parseSignedKeyPair(allocator, root.get("signedPreKey").?);

    creds.registrationId = @intCast(root.get("registrationId").?.integer);
    creds.advSecretKey = try decodeBase64Bytes(32, root.get("advSecretKey").?.string);

    return AuthState{
        .creds = creds,
        .allocator = allocator,
    };
}

fn parseKeyPair(allocator: std.mem.Allocator, value: json.Value) !KeyPair {
    _ = allocator;
    const obj = value.object;
    return KeyPair{
        .public = try parseBufferField(32, obj.get("public").?),
        .private = try parseBufferField(32, obj.get("private").?),
    };
}

fn parseSignedKeyPair(allocator: std.mem.Allocator, value: json.Value) !SignedKeyPair {
    const obj = value.object;
    return SignedKeyPair{
        .keyPair = try parseKeyPair(allocator, obj.get("keyPair").?),
        .signature = try parseBufferField(64, obj.get("signature").?),
        .keyId = @intCast(obj.get("keyId").?.integer),
    };
}

/// Handle both Buffer-style {type, data} and base64 string
fn parseBufferField(comptime N: usize, value: json.Value) ![N]u8 {
    switch (value) {
        .string => |s| return try decodeBase64Bytes(N, s),
        .object => |obj| {
            // { type: "Buffer", data: [bytes...] }
            const data = obj.get("data").?.array;
            var result: [N]u8 = undefined;
            for (data.items, 0..) |item, i| {
                if (i >= N) break;
                result[i] = @intCast(item.integer);
            }
            return result;
        },
        else => return error.InvalidBufferFormat,
    }
}

fn decodeBase64Bytes(comptime N: usize, str: []const u8) ![N]u8 {
    var result: [N]u8 = undefined;
    const decoder = std.base64.standard.Decoder;
    try decoder.decode(&result, str);
    return result;
}

fn serializeCredsJson(allocator: std.mem.Allocator, writer: anytype, creds: *const Creds) !void {
    _ = allocator;
    // Write JSON matching Baileys format with base64 encoding
    try writer.writeAll("{\n");
    try writeKeyPairJson(writer, "noiseKey", creds.noiseKey);
    // ... write remaining fields
    try writer.writeAll("\n}");
}

fn writeKeyPairJson(writer: anytype, name: []const u8, kp: KeyPair) !void {
    var buf: [128]u8 = undefined;
    const encoder = std.base64.standard.Encoder;

    const pub_b64 = encoder.encode(&buf, &kp.public);
    try writer.print("  \"{s}\": {{ \"public\": \"{s}\"", .{ name, pub_b64 });

    const priv_b64 = encoder.encode(&buf, &kp.private);
    try writer.print(", \"private\": \"{s}\" }},\n", .{priv_b64});
}
```

## Noise Protocol Handler

This is the heart of the connection encryption:

```zig
// src/crypto/noise.zig
const std = @import("std");
const crypto = std.crypto;

const NOISE_MODE = "Noise_XX_25519_AESGCM_SHA256\x00\x00\x00\x00";
const WA_HEADER = [_]u8{ 'W', 'A', 6, 2 }; // WhatsApp v2 header

pub const NoiseHandler = struct {
    hash: [32]u8,
    salt: [32]u8,
    enc_key: [32]u8,
    dec_key: [32]u8,
    write_counter: u64 = 0,
    read_counter: u64 = 0,
    is_finished: bool = false,
    sent_intro: bool = false,
    allocator: std.mem.Allocator,

    pub fn init(allocator: std.mem.Allocator, noise_pubkey: [32]u8) NoiseHandler {
        var hash: [32]u8 = undefined;

        if (NOISE_MODE.len == 32) {
            @memcpy(&hash, NOISE_MODE[0..32]);
        } else {
            crypto.hash.sha2.Sha256.hash(NOISE_MODE, &hash, .{});
        }

        var self = NoiseHandler{
            .hash = hash,
            .salt = hash,
            .enc_key = hash,
            .dec_key = hash,
            .allocator = allocator,
        };

        self.authenticate(&WA_HEADER);
        self.authenticate(&noise_pubkey);

        return self;
    }

    pub fn authenticate(self: *NoiseHandler, data: []const u8) void {
        if (self.is_finished) return;

        var hasher = crypto.hash.sha2.Sha256.init(.{});
        hasher.update(&self.hash);
        hasher.update(data);
        hasher.final(&self.hash);
    }

    pub fn encrypt(self: *NoiseHandler, plaintext: []const u8, out: []u8) ![]u8 {
        const Aes = crypto.aead.aes_gcm.Aes256Gcm;

        var nonce: [12]u8 = [_]u8{0} ** 12;
        std.mem.writeInt(u64, nonce[4..12], self.write_counter, .big);

        const tag_start = plaintext.len;
        var tag: [16]u8 = undefined;

        Aes.encrypt(
            out[0..plaintext.len],
            &tag,
            plaintext,
            &self.hash, // AAD
            nonce,
            self.enc_key,
        );

        @memcpy(out[tag_start..][0..16], &tag);

        self.write_counter += 1;
        self.authenticate(out[0 .. plaintext.len + 16]);

        return out[0 .. plaintext.len + 16];
    }

    pub fn decrypt(self: *NoiseHandler, ciphertext: []const u8, out: []u8) ![]u8 {
        const Aes = crypto.aead.aes_gcm.Aes256Gcm;

        var nonce: [12]u8 = [_]u8{0} ** 12;
        const counter = if (self.is_finished) self.read_counter else self.write_counter;
        std.mem.writeInt(u64, nonce[4..12], counter, .big);

        const ct_len = ciphertext.len - 16;
        var tag: [16]u8 = undefined;
        @memcpy(&tag, ciphertext[ct_len..]);

        try Aes.decrypt(
            out[0..ct_len],
            ciphertext[0..ct_len],
            tag,
            &self.hash, // AAD
            nonce,
            self.dec_key,
        );

        if (self.is_finished) {
            self.read_counter += 1;
        } else {
            self.write_counter += 1;
        }
        self.authenticate(ciphertext);

        return out[0..ct_len];
    }

    /// HKDF mixing of new key material
    pub fn mixIntoKey(self: *NoiseHandler, data: []const u8) void {
        const Hmac = crypto.auth.hmac.sha2.HmacSha256;
        const Hkdf = crypto.kdf.hkdf.Hkdf(Hmac);

        const prk = Hkdf.extract(&self.salt, data);

        var output: [64]u8 = undefined;
        Hkdf.expand(&output, "", prk);

        @memcpy(&self.salt, output[0..32]);
        @memcpy(&self.enc_key, output[32..64]);
        @memcpy(&self.dec_key, output[32..64]);

        self.read_counter = 0;
        self.write_counter = 0;
    }

    pub fn mixSharedSecret(self: *NoiseHandler, priv: [32]u8, pub_key: [32]u8) !void {
        const shared = try crypto.dh.X25519.scalarmult(priv, pub_key);
        self.mixIntoKey(&shared);
    }

    pub fn finishInit(self: *NoiseHandler) void {
        const Hmac = crypto.auth.hmac.sha2.HmacSha256;
        const Hkdf = crypto.kdf.hkdf.Hkdf(Hmac);

        const prk = Hkdf.extract(&self.salt, "");
        var output: [64]u8 = undefined;
        Hkdf.expand(&output, "", prk);

        @memcpy(&self.enc_key, output[0..32]);
        @memcpy(&self.dec_key, output[32..64]);

        self.hash = undefined;
        self.read_counter = 0;
        self.write_counter = 0;
        self.is_finished = true;
    }

    /// Wrap a frame with length prefix (and intro header on first send)
    pub fn encodeFrame(self: *NoiseHandler, data: []const u8, out: *std.ArrayList(u8)) !void {
        var payload = data;
        var enc_buf: [8192]u8 = undefined;

        if (self.is_finished) {
            payload = try self.encrypt(data, &enc_buf);
        }

        if (!self.sent_intro) {
            try out.appendSlice(&WA_HEADER);
            self.sent_intro = true;
        }

        // 3-byte big-endian length
        const len = payload.len;
        try out.append(@intCast((len >> 16) & 0xff));
        try out.append(@intCast((len >> 8) & 0xff));
        try out.append(@intCast(len & 0xff));
        try out.appendSlice(payload);
    }
};
