// src/socket/websocket.zig
const std = @import("std");
const net = std.net;
const crypto = std.crypto;

pub const WHATSAPP_HOST = "web.whatsapp.com";
pub const WHATSAPP_PORT = 443;
pub const WS_PATH = "/ws/chat";

pub const WebSocket = struct {
    stream: net.Stream,
    tls_client: crypto.tls.Client,
    allocator: std.mem.Allocator,
    read_buffer: [16384]u8 = undefined,

    pub fn connect(allocator: std.mem.Allocator) !WebSocket {
        const stream = try net.tcpConnectToHost(allocator, WHATSAPP_HOST, WHATSAPP_PORT);

        var ca_bundle = crypto.Certificate.Bundle{};
        try ca_bundle.rescan(allocator);

        const tls_client = try crypto.tls.Client.init(stream, .{
            .host = .{ .explicit = WHATSAPP_HOST },
            .ca = .{ .bundle = ca_bundle },
        });

        var ws = WebSocket{
            .stream = stream,
            .tls_client = tls_client,
            .allocator = allocator,
        };

        try ws.performHandshake();
        return ws;
    }

    fn performHandshake(self: *WebSocket) !void {
        // Generate random WebSocket key
        var key_bytes: [16]u8 = undefined;
        crypto.random.bytes(&key_bytes);
        var key_b64: [24]u8 = undefined;
        _ = std.base64.standard.Encoder.encode(&key_b64, &key_bytes);

        var req_buf: [512]u8 = undefined;
        const request = try std.fmt.bufPrint(&req_buf,
            "GET {s} HTTP/1.1\r\n" ++
            "Host: {s}\r\n" ++
            "Upgrade: websocket\r\n" ++
            "Connection: Upgrade\r\n" ++
            "Sec-WebSocket-Key: {s}\r\n" ++
            "Sec-WebSocket-Version: 13\r\n" ++
            "Origin: https://web.whatsapp.com\r\n" ++
            "\r\n",
            .{ WS_PATH, WHATSAPP_HOST, key_b64 });

        try self.tls_client.writeAll(self.stream, request);

        // Read handshake response
        var resp_buf: [1024]u8 = undefined;
        const n = try self.tls_client.read(self.stream, &resp_buf);

        if (std.mem.indexOf(u8, resp_buf[0..n], "101") == null) {
            return error.WebSocketHandshakeFailed;
        }
    }

    /// Send a WebSocket binary frame
    pub fn sendFrame(self: *WebSocket, payload: []const u8) !void {
        var header: [14]u8 = undefined;
        var header_len: usize = 0;

        header[0] = 0x82; // FIN + binary opcode

        // Client frames must be masked
        if (payload.len < 126) {
            header[1] = 0x80 | @as(u8, @intCast(payload.len));
            header_len = 2;
        } else if (payload.len < 65536) {
            header[1] = 0x80 | 126;
            std.mem.writeInt(u16, header[2..4], @intCast(payload.len), .big);
            header_len = 4;
        } else {
            header[1] = 0x80 | 127;
            std.mem.writeInt(u64, header[2..10], payload.len, .big);
            header_len = 10;
        }

        // Masking key
        var mask: [4]u8 = undefined;
        crypto.random.bytes(&mask);
        @memcpy(header[header_len..][0..4], &mask);
        header_len += 4;

        try self.tls_client.writeAll(self.stream, header[0..header_len]);

        // Mask and send payload
        const masked = try self.allocator.alloc(u8, payload.len);
        defer self.allocator.free(masked);
        for (payload, 0..) |b, i| {
            masked[i] = b ^ mask[i % 4];
        }
        try self.tls_client.writeAll(self.stream, masked);
    }

    /// Receive a WebSocket frame, returning the payload
    pub fn recvFrame(self: *WebSocket, out: *std.ArrayList(u8)) !void {
        var hdr: [2]u8 = undefined;
        try self.readExact(&hdr);

        const opcode = hdr[0] & 0x0f;
        _ = opcode;
        const masked = (hdr[1] & 0x80) != 0;
        var payload_len: u64 = hdr[1] & 0x7f;

        if (payload_len == 126) {
            var ext: [2]u8 = undefined;
            try self.readExact(&ext);
            payload_len = std.mem.readInt(u16, &ext, .big);
        } else if (payload_len == 127) {
            var ext: [8]u8 = undefined;
            try self.readExact(&ext);
            payload_len = std.mem.readInt(u64, &ext, .big);
        }

        var mask: [4]u8 = undefined;
        if (masked) try self.readExact(&mask);

        try out.resize(payload_len);
        try self.readExact(out.items);

        if (masked) {
            for (out.items, 0..) |*b, i| {
                b.* ^= mask[i % 4];
            }
        }
    }

    fn readExact(self: *WebSocket, buf: []u8) !void {
        var total: usize = 0;
        while (total < buf.len) {
            const n = try self.tls_client.read(self.stream, buf[total..]);
            if (n == 0) return error.ConnectionClosed;
            total += n;
        }
    }

    pub fn close(self: *WebSocket) void {
        self.stream.close();
    }
};
