    ctx.fillStyle = `rgba(255,255,255,${0.3 + s.r/3})`;
    ctx.beginPath();
    ctx.arc(s.x, s.y, s.r, 0, Math.PI*2);
    ctx.fill();
  });

  // items
  items.forEach(it => {
    if (it.type === 'bomb') {
      ctx.save();
      ctx.translate(it.x, it.y);
      ctx.fillStyle = '#2d3436';
      ctx.shadowColor = '#ff4757';
      ctx.shadowBlur = 10;
      ctx.beginPath();
      ctx.arc(0, 0, it.size, 0, Math.PI*2);
      ctx.fill();
      ctx.shadowBlur = 0;
      ctx.strokeStyle = '#ff6b6b';
      ctx.lineWidth = 2;
      ctx.beginPath();
      ctx.moveTo(0, -it.size);
      ctx.lineTo(4, -it.size - 8);
      ctx.stroke();
      ctx.fillStyle = '#ffa502';
      ctx.beginPath();
      ctx.arc(5, -it.size - 9, 2.5, 0, Math.PI*2);
      ctx.fill();
      ctx.restore();
    } else {
      drawStar(it.x, it.y, it.size, 5,
        it.type === 'gold' ? '#ffd700' : '#74b9ff', it.rot);
    }
  });

  // particles
  particles.forEach(p => {
    ctx.globalAlpha = Math.max(0, p.life);
    ctx.fillStyle = p.color;
    ctx.beginPath();
    ctx.arc(p.x, p.y, 3, 0, Math.PI*2);
    ctx.fill();
  });
  ctx.globalAlpha = 1;

  // basket
  if (running) {
    const grad = ctx.createLinearGradient(0, basket.y, 0, basket.y + basket.h);
    grad.addColorStop(0, '#a29bfe');
    grad.addColorStop(1, '#6c5ce7');
    ctx.fillStyle = grad;
    ctx.shadowColor = '#6c5ce7';
    ctx.shadowBlur = 15;
    ctx.beginPath();
    ctx.roundRect(basket.x - basket.w/2, basket.y, basket.w, basket.h, 8);
    ctx.fill();
    ctx.shadowBlur = 0;
    // rim
    ctx.fillStyle = '#dfe6e9';
    ctx.fillRect(basket.x - basket.w/2, basket.y, basket.w, 4);
  }
}

function loop() {
  update();
  draw();
  requestAnimationFrame(loop);
}

function startGame() {
  score = 0; lives = 3; running = true;
  items = []; particles = [];
  spawnTimer = 0; spawnInterval = 90; speedMult = 1;
  scoreEl.textContent = 0;
  livesEl.textContent = 3;
  overlay.classList.add('hidden');
}

function gameOver() {
  running = false;
  if (score > best) {
    best = score;
    localStorage.setItem('starBest', best);
    bestEl.textContent = best;
  }
  overlay.querySelector('h1').textContent = '💀 Game Over';
  overlay.querySelector('p').innerHTML =
    `You scored <b style="color:#ffd700">${score}</b> points!<br>Best: ${best}`;
  startBtn.textContent = 'Play Again';
  overlay.classList.remove('hidden');
}

startBtn.addEventListener('click', startGame);
loop();
</script>
</body>
</html>
```

**How to play:**
